import Foundation
import XPDataProcessor

@objcMembers
open class XPVehicleSDK : NSObject {
    public static let shared = XPVehicleSDK()

    public let vehicleManager: VehicleManager = VehicleManager()

    public var isPullAlive: Bool = false

    private override init() {
        super.init()
        Log.i(tag: "SDK生命期", "init");
    }

    deinit {
        Log.i(tag: "SDK生命期", "deinit");
    }

    func checkText() {
        Log.i(tag: "SDK文案测试", "<intelligent_prediction>:", "intelligent_prediction".sdkString);
        Log.i(tag: "SDK文案测试", "<timeout_try_again>:", "timeout_try_again".sdkString);
        Log.i(tag: "SDK文案测试", "国内版应该返回 nil， 海外应该直接返回 key，确保海外蓝牙错误不会弹出中文Toast <test_not_exist_key>:", "test_not_exist_key".sdkString);
#if DEBUG
    #if APP_ENV_INTL
        assert("test_not_exist_key".sdkString == "test_not_exist_key", "文案桥接出现错误")
        assert("timeout_try_again".sdkString != nil, "文案桥接出现错误")
    #else
        assert("test_not_exist_key".sdkString == nil, "文案桥接出现错误")
        assert("timeout_try_again".sdkString != nil, "文案桥接出现错误")
    #endif
#endif
    }

    public static func setHttpProxy(_ http: HttpProtocol) {
        ProxyManger.shared.httpProxy = http
    }


    public static func setOTAConfigProxy(_ otaConfig: OTAConfigProtocol) {
        ProxyManger.shared.otaConfigProxy = otaConfig
    }

    public static func setOCMAppSettingsProxy(_ ocmAppSettings: OCMAppSettingsProtocol) {
        ProxyManger.shared.ocmAppSettingsProxy = ocmAppSettings
    }

    public static func setLogProxy(_ log: LogProtocol) {
        ProxyManger.shared.logProxy = log
    }

    public static func setDbProxy(_ db: DatabaseProtocol) {
        ProxyManger.shared.dbProxy = db
    }

    public static func setErrorProxy(_ errorHandler: ErrorProtocol) {
        ProxyManger.shared.errorProxy = errorHandler
    }

    public static func setStatisticsProxy(_ statistics: StatisticsProtocol) {
        ProxyManger.shared.statisticsProxy = statistics
    }

    public static func setMqttAccountProxy(_ mqttAccount: MqttAccountProtocol) {
        ProxyManger.shared.mqttAccountProxy = mqttAccount
    }

    public static func setKeySettingDataProxy(_ keySettingData: KeySettingDataProtocol) {
        ProxyManger.shared.keySettingProxy = keySettingData
    }

    public static func setTextProxy(_ text: TextProtocol) {
        ProxyManger.shared.textProxy = text
    }

    public static func setup(launchOptions: [String: Any]?) {
        Log.i(tag: "SDK生命期", "setupWithLaunchOptions:", launchOptions);

        DataProxyManager.shared().logProxy = DataLogBridge.shared
        XiaopengCmdFactory.shared.registerAllCmdPlugins()
        MonaCmdFactory.shared.registerAllCmdPlugins()
        initializeTools(launchOptions: launchOptions)
        self.shared.vehicleManager.setup()

        self.shared.checkText()
    }

    public static func exit() {
        Log.i(tag: "SDK生命期", "exit");
    }

}

extension XPVehicleSDK {

    static func initializeTools(launchOptions: [String: Any]?) {

        // 网络 监听
        NetworkMonitor.shared

        // app 前后台状态
        ApplicationState.shared

        // Mona监控
        CarService.initializeTools()

        AppRunState.shared.backgroundTime = XPVehicleSDK.shared.isPullAlive ? CACurrentMediaTime() : 0

    }
}

import Foundation


@objc(XPDigitalKeyManagerProtocol)
public protocol DigitalKeyManagerProtocol : NSObjectProtocol {

    // 获取当前车数字钥匙列表
    var digitalKeyList: [DigitalKey] { get }

    // 指定钥匙分类获取数字钥匙
    func digitalKey(keyCategory: DigitalKeyCategory) -> DigitalKey?

    // 指定钥匙卡片类型获取数字钥匙
    func digitalKey(keyCardType: KeyCardType) -> DigitalKey?

    // 指定钥匙卡片类型获取数字钥匙列表原始数据（字典）
    func digitalKeyList(keyCardType: KeyCardType) -> Array<Any>?

    // 指定钥匙卡片类型获取数字钥匙列表
    func digitalKeyListObject(keyCardType: KeyCardType) -> [DigitalKey]?

    // 指定多个钥匙卡片类型获取数字钥匙列表
    func digitalMultiKeyList(keyCardTypeArray: Array<NSNumber>) -> Array<Any>?

    var isTboxBad: Bool { get } // 是否TBOX异常标志

    // 自动查找有效的私有蓝牙钥匙
    func validBlePrivateKey() -> DigitalKey?

    // 是否存在待激活的数字钥匙
    func existToBeActivateBLEKey() -> Bool

    // 是否存在可用的私有蓝牙钥匙
    func existValidBlePrivateKey() -> Bool

    // 是否存在可用的蓝牙钥匙
    func existValidBleKey() -> Bool

    //禁用安全钥匙，转证书钥匙
    func disableSafeKey()

    //可用的蓝牙钥匙类型
    func vaildBleKeyCategory() -> DigitalKeyCategory 

    // 设置所以指令是否免生物识别验证，默认否（用户在弹窗设置后本地缓存）
    func configNoBioVerfy(noBioVerfy: Bool)

    // 指定钥匙分类创建钥匙，目前只支持手机蓝牙自研钥匙（PHONE_BLE_KEY）
    func createKey(keyCategory: DigitalKeyCategory, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 指定钥匙分类删除钥匙，目前只支持手机蓝牙自研钥匙（PHONE_BLE_KEY）
    func removeKey(keyCategory: DigitalKeyCategory, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)
    // 创建数字钥匙
    func createKey(keyCardType: KeyCardType, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 创建数字蓝牙钥匙（PHONE_BLE_KEY）
    func createKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 删除数字蓝牙钥匙
    func removeKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 删除NFC钥匙
    func removeNfcKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    //通过网络接口设置解闭锁开关，仅用于CCC钥匙
    func setDigitalKeySwitch(lockParam: CarKeyAutoLockRequestParam, vin: String, uid: UInt64, success:  ((Bool) -> Void)?, failed: ((VehicleError) -> Void)?)

    func refreshRemoteKeyList()

    // 报文失效，清理本地数据
    func clearKeyMessage()
    var selfCalibration: PollingSelfCalibrationProtocol? { get }

    // polling 开关状态变更
    func pollingStateChange(pollingMode: VehiclePollingMode)

    func pollingEnableSwitchChange(pollingEnableSwitch: Bool) // pollingEnable 开关状态变更

    // polling 解锁距离变更
    func pollingUnlockDistanceChange(unlockDistance: Float)

    // polling 闭锁距离变更
    func pollingLockDistanceChange(lockDistance: Float)

    // polling 感应模式变更
    func pollingWelcomeModeChange(welcomeMode: Bool)

    // polling 自标定数据变更
    func pollingSelfCalibrationDataChange(txPowerArray: Array<String>?)

    /// 获取数字钥匙云端设置
    /// - Parameters:
    ///   - vin: 车架号
    ///   - device: 移动设备型号，用于区分不同设备的设置
    ///   - success: 成功回调
    ///   - failed: 失败回调
    func requestKeySettings(vin: String, device: String?, success: @escaping VehicleDigitalKeySuccessResponseCallback<KeySettingInfo>, failed: @escaping VehicleFailedCallback<VehicleError>)

    /// 上传数字钥匙设置到云端
    /// - Parameters:
    ///   - vin: 车架号
    ///   - device: 移动设备型号，用于区分不同设备的设置
    ///   - settings: 设置内容
    ///   - success: 成功回调
    ///   - failed: 失败回调
    func uploadKeySettings(vin: String, device: String?, settings: KeySettingInfo, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    //当前报文剩余数量，用于一些特定场景策略
    func certMessageCount() -> Int

    // 非数字钥匙3.0车型 非E28车可用
    func setIsDriverMode(_ isDriverMode: Bool) // 设置是否主驾模式

    func getCurrentCarKeyPlugin() -> CarKeyPassAccessProtocol?

}

