1	//
2	//  DigitalKeyManager.swift
3	//  XPVehicleSDK
4	//
5	//  Created by Xpeng on 2023/12/5.
6	//
7	
8	import Foundation
9	import Combine
10	
11	@objc(XPDigitalKeyManagerDelegate)
12	protocol DigitalKeyManagerDelegate : NSObjectProtocol {
13	    @objc optional func willCreateKey(vin: String!, keyCardType: KeyCardType)
14	    @objc optional func didCreateKey(vin: String!, keyCardType: KeyCardType, success: Bool)
15	    @objc optional func willRemoveKey(vin: String!, keyCardType: KeyCardType)
16	    @objc optional func didRemoveKey(vin: String!, keyCardType: KeyCardType, success: Bool)
17	    
18	    @objc optional func didLoadKeys(vin: String!)
19	}
20	
21	//@objc(XPDigitalKeyManager)
22	class DigitalKeyManager: NSObject, DigitalKeyManagerProtocol, ObservableObject, MonaKeyStatusDelegate {
23	
24	    var uid: UInt64                             // 用户UID
25	    @Published public var bleInfo: BLEInfo?     // BLE 信息
26	
27	    @objc @Published public var digitalKeyList: [DigitalKey] = []
28	    
29	    var isTboxBad: Bool = false          // TBOX 是否在线
30	    
31	    private var _selfCalibration: PollingSelfCalibrationProtocol?
32	    var selfCalibration: PollingSelfCalibrationProtocol? {
33	        return _selfCalibration
34	    }
35	
36	    var cancellables = Set<AnyCancellable>()
37	    let keyTypeList: [Int] // KeyCardType 支持的钥匙类型
38	    let vehicle: VehicleInfo.Vehicle
39	    weak var delegate: DigitalKeyManagerDelegate?
40	    var createKeyPlugin: DigitalKeyManagerPluginProtocol?
41	    var removeKeyPlugin: DigitalKeyManagerPluginProtocol?
42	    let vehiclePreference: VehiclePreference
43	    weak var communication: VehicleCommunication?
44	    var fetchMacTimer: Timer?
45	    static var staticPlugin: [String:DigitalKeyManagerPluginProtocol?] = [:]
46	    static let serialPluginQueue = DispatchQueue(label: "com.xpvehicle.sdk.digitalkey.serialQueue")
47	    static var keyManagerMap: [KeyCardType: AnyObject] = [
48	        KeyCardType.SAFE:IFAAKeyManager.self,
49	        KeyCardType.CERT:IFAAKeyManager.self,
50	        KeyCardType.SELF:SelfKeyManager.self,
51	        KeyCardType.MONA_BLE:MonaKeyManager.self,
52	        KeyCardType.NFC_WATCH:NFCKeyManager.self,
53	        KeyCardType.SELF_V3:SelfKeyV3Manager.self,
54	        KeyCardType.CCC:SelfKeyV3Manager.self
55	    ]
56	    
57	    private var _carKeyPlugin: CarKeyPassAccessProtocol?
58	    private var currentCCCVid: String?
59	
60	    var carKeyPlugin: CarKeyPassAccessProtocol? {
61	        guard let cccVid = vehiclePreference.extInfo?.cccVid else { return nil }
62	        if !vehiclePreference.function.CCC_DK_THIRD {
63	            return nil;
64	        }
65	        if _carKeyPlugin == nil || currentCCCVid != cccVid {
66	            guard CarKeyConditionCheck.isSupportCarKeySoftware(cccVid: vehiclePreference.extInfo?.cccVid, bleKeyVersion: Int(vehiclePreference.abilityConfig.bleKeyVersion.rawValue), isSupportCCC: vehiclePreference.function.CCC_DK_THIRD) else { return nil }
67	            let plugin = CarKeyPassAccesser(cccVid: cccVid, delegate: self)
68	            _carKeyPlugin = plugin
69	            currentCCCVid = cccVid
70	            plugin.initConfigure()
71	        }
72	        return _carKeyPlugin
73	    }
74	    
75	    public init(uid: UInt64, vehicle: VehicleInfo.Vehicle!, keyTypeList: [Int], vehiclePreference: VehiclePreference, communication: VehicleCommunication? = nil) {
76	        Log.i("DigitalKeyManager init vin:\(vehicle.vin ?? "")")
77	        self.uid = uid
78	        self.vehicle = vehicle
79	        self.keyTypeList = keyTypeList
80	        self.vehiclePreference = vehiclePreference
81	        self.communication = communication
82	        super.init()
83	        
84	        loadAllDigitalKey(uid: uid, isFromInit: true)
85	        
86	        NotificationCenter.default.addObserver(self, selector: #selector(refreshDigitalKeyFromNotification), name: VehicleNotification.CallBackConnectAuthError, object: nil)
87	        NotificationCenter.default.addObserver(self, selector: #selector(connectStateChanged), name: VehicleNotification.BLEConnectStateChanged, object: nil)
88	        NotificationCenter.default.addObserver(self, selector: #selector(networkResumeAction), name: VehicleNotification.NetworkResume, object: nil)
89	        NotificationCenter.default.addObserver(self, selector: #selector(tboxRunStateNotification), name: VehicleNotification.tboxRunStateNotification, object: nil)
90	        
91	        // 自标定协议实现
92	        var calibrationVer = BleSelfCalibrationVersion.v1
93	        if vehiclePreference.abilityConfig.isSupportPollingV1 == true {
94	            calibrationVer = .v1
95	        } else if vehiclePreference.abilityConfig.isSupportPollingV2 == true {
96	            calibrationVer = .v2
97	        } else {
98	            calibrationVer = .v3
99	        }
100	        
101	        if let communication = communication {
102	            _selfCalibration = SelfCalibrationManger(communication: communication, version: calibrationVer)
103	        }
104	        
105	        CarService.registerMonaKeyListener(listener: self)
106	        //        mockDigitalKey("00:60:37:6b:4b:5d")  // BLE_MOCK 本地调试蓝牙件时打开，但不要提交
107	        Log.i("DigitalKeyManager init end vin:\(vehicle.vin ?? "")")
108	    }
109	    
110	    deinit {
111	        Log.i(tag:"DigitalKeyManager", "DigitalKeyManager deinit")
112	        NotificationCenter.default.removeObserver(self)
113	        CarService.unregisterMonaKeyListener(listener: self)
114	        self.stopTimerMacAddress()
115	    }
116	    
117	    func mockDigitalKey(_ address: String) {
118	        let digitalKey = DigitalKey(uid: uid, vin: vehicle.vin ?? "", keyCardType: KeyCardType.SELF, cardNo: "1000")
119	        setDigitalKeyList(digitalKeyList: [digitalKey])
120	        let bleInfo = BLEInfo()
121	        bleInfo.macAddress = address;
122	        bleInfo.useScanUUIDs = false
123	        digitalKey.bleInfo = bleInfo
124	        digitalKey._keyMessageManager = MockKeyMessageManager(uid: self.uid, vin: vehicle.vin ?? "", cardNo: digitalKey.cardNo)
125	        
126	        DispatchQueue.main.async { [weak self] in
127	            self?.repareBleInfo()
128	            self?.delegate?.didLoadKeys?(vin: self?.vehicle.vin)
129	        }
130	    }
131	    
132	    func setDigitalKeyList(digitalKeyList: [DigitalKey]) {
133	        Log.i("更新数字钥匙列表：", digitalKeyList)
134	        if (digitalKeyList.count > 0) {
135	            self.digitalKeyList = digitalKeyList
136	        }
137	    }
138	    
139	    func appendDigitalKey(digitalKey: DigitalKey) -> DigitalKey? {
140	        let arr = self.digitalMultiKeyArray(keyCardType: digitalKey.keyCardType)
141	        for key in arr {
142	            if key.cardNo == digitalKey.cardNo {
143	                if let index = self.digitalKeyList.firstIndex(of: key) {
144	                    self.digitalKeyList.remove(at: index) // 删除旧钥匙
145	                }
146	            }
147	        }
148	        self.digitalKeyList.append(digitalKey)
149	        Log.i(tag:"DigitalKeyManager", "  数字钥匙报文剩余:", digitalKey.keyMessageCount() )
150	
151	        return digitalKey
152	    }
153	    
154	    func repareBleInfo() {
155	        var bleInfo: BLEInfo? = nil
156	        if self.digitalKey(keyCardType: .SELF) != nil {
157	            bleInfo = self.digitalKey(keyCardType: .SELF)!.bleInfo
158	        } else if self.digitalKey(keyCardType: .CERT) != nil {
159	            bleInfo = self.digitalKey(keyCardType: .CERT)!.bleInfo
160	        } else if self.digitalKey(keyCardType: .SAFE) != nil {
161	            bleInfo = self.digitalKey(keyCardType: .SAFE)!.bleInfo
162	        } else if self.digitalKey(keyCardType: .MONA_BLE) != nil {
163	            bleInfo = self.digitalKey(keyCardType: .MONA_BLE)!.bleInfo
164	        } else if self.digitalKey(keyCardType: .SELF_V3) != nil {
165	            bleInfo = self.digitalKey(keyCardType: .SELF_V3)!.bleInfo
166	        }
167	        Log.i(tag:"DigitalKeyManager", "设置数字钥匙BLEInfo: ", bleInfo ?? "<Null>")
168	        if (self.bleInfo != bleInfo) {
169	            self.bleInfo = bleInfo
170	        }
171	    }
172	        
173	    // 从数据库中加载该车辆所有的数字钥匙，请求云端数据
174	    func loadAllDigitalKey(uid: UInt64!, isFromInit: Bool!) {
175	        Log.i(tag:"DigitalKeyManager", "数字钥匙加载 vin: ", self.vehicle.vin ?? "")
176	        if (self.vehicle.vin!.count > 0) {
177	            // 暂时使用同步加载数据库，不然会出现UI层车辆切换完毕但是钥匙还未Ready，激活按钮状态不对的问题
178	            let digitalKeyList = DigitalKey.queryDigitalKeyList(vin: self.vehicle.vin ?? "")
179	            Log.i(tag:"DigitalKeyManager", "数字钥匙加载缓存结果(\(digitalKeyList.count)): ", digitalKeyList)
180	            setDigitalKeyList(digitalKeyList: digitalKeyList)
