390	            } else {
391	                callBack(false, nil)
392	            }
393	        }
394	        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.requestVehicleVerifyCode, payload:["typeList":[1, 2],"vin":self.vehicle.vin ?? ""],callback: responseCallback)
395	    }
