893	        switch code {
894	        case 0xF2:  // 钥匙已拉黑
895	            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.ban.rawValue])
