959	            var keyCardType: KeyCardType = .NONE
960	            if allowCallMonaSDK(vehiclePreference: vehiclePreference) {
961	                keyCardType = KeyCardType.MONA_BLE
962	            } else if vehiclePreference.abilityConfig.bleKeyVersion == BleKeyProtocolVesion.V3 {
963	                keyCardType = KeyCardType.SELF_V3
964	            } else if let pluginSelf = generatePlugin(uid: uid, keyCardType: KeyCardType.SELF, vehicle: vehicle) {
965	                keyCardType = KeyCardType.SELF
966	            }
967	            if DigitalKeyManager.staticPlugin[DigitalKeyManager.pluginKey(uid: uid, vin: vehicle.vin ?? "", keyCardType: keyCardType)] != nil {
