    public func createKey(keyCardType: KeyCardType, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        let key: DigitalKey? = self.digitalKey(keyCardType: keyCardType)
        if (key != nil && key?.isValidKey() == true) {
            Log.i(tag:"DigitalKeyManager", "数字钥匙创建 \(keyCardType) createKey 该类型的钥匙已经存在，不允许重复创建")
            let resp = VehicleError(code: .EnvironmentError, desc: "执行失败(重复创建)")
            failed(resp)
            return
        }

        let plugin = self.createPlugin(keyCardType: keyCardType)
        if (plugin == nil) {
            let resp = VehicleError(code: .NotSupported, desc: "尚未支持，操作失败")
            failed(resp)
            return
        }

        self.delegate?.willCreateKey?(vin: self.vehicle.vin, keyCardType: keyCardType)
        self.createKeyPlugin = plugin

        plugin!.createKey(success: { data in
            if (data != nil && data!.digitalKeyList != nil && (data!.digitalKeyList.count ?? 0) > 0) {
                for digitalKeyItem in data!.digitalKeyList{
                    digitalKeyItem.save()
                    let digitalKeyAppend = self.appendDigitalKey(digitalKey: digitalKeyItem)
                    if (digitalKeyAppend != nil && data!.authDataList != nil) {
                        digitalKeyAppend!.saveAuthDataList(dataList: data!.authDataList!)
                    }
                }
                var digitalKey: DigitalKey?
                if data!.digitalKeyList.count > 1 {
                    digitalKey = data!.digitalKeyList[1]
                } else {
                    digitalKey = data!.digitalKeyList[0]
                }
                self.delegate?.didCreateKey?(vin: self.vehicle.vin, keyCardType: keyCardType, success: true)
                Log.i(tag:"DigitalKeyManager", "创建钥匙后当前报文数量:", digitalKey?.keyMessageCount())

                let test: BLEKeyHttpRequestCallback<BLEInfo> = { response in
                    if (response.code == 200 && response.data != nil) {
                        let info = response.data!
                        let macAddress = (info.macAddress ?? "") as String
                        Log.i(tag:"DigitalKeyManager", "下载到Mac地址 macAddress:", macAddress)
                        if (self.vehicle.vehicleTypeCode != "ED") {
                            info.useScanUUIDs = true
                        }
                        digitalKey?.bleInfo = info
                        self.bleInfo = info // 业务方会监听 self.bleInfo 变化，重连蓝牙
                        let klist = DigitalKey.queryDigitalKeyList(vin: self.vehicle.vin!)
                        Log.i(tag:"DigitalKeyManager", "数字钥匙写入后加载结果: ", klist)
                        if digitalKey?.bleKeyCard != nil && digitalKey?.bleKeyCard?.status == XPBLEKeyCardStatus.XPBLEKeyCardStatusReadyToActivate {
                            digitalKey?.bleKeyCard?.status = XPBLEKeyCardStatus.XPBLEKeyCardStatusToBeActivated
                            if let saveKey = digitalKey {
                                saveKey.save()
                                let digitalKeyAppend = self.appendDigitalKey(digitalKey: saveKey)
                            }
                            self.createKey(keyCardType: KeyCardType.MONA_BLE, success: success, failed: failed)
                        }else {
                            if let saveKey = digitalKey {
                                saveKey.save()
                                let digitalKeyAppend = self.appendDigitalKey(digitalKey: saveKey)
                            }
                            success(digitalKey)
                        }
                    } else {
                        self.fetchMac()
                        success(digitalKey)
                    }
                }
                BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.bleInfo, payload: ["vin": self.vehicle.vin ?? ""], callback: test)
            } else {
                self.delegate?.didCreateKey?(vin: self.vehicle.vin, keyCardType: keyCardType, success: false)
                let resp = VehicleError(code: .UnknownError, desc: "执行失败")
                failed(resp)
            }
            self.createKeyPlugin = nil
        }, failed: { error in
            if (error.digitalKey != nil) {
                error.digitalKey!.save()
                _ = self.appendDigitalKey(digitalKey: error.digitalKey!)
            }
            self.delegate?.didCreateKey?(vin: self.vehicle.vin, keyCardType: keyCardType, success: false)
            failed(VehicleError(code: VehicleErrorCode.UnknownError, msg: error.msg, desc: error.desc))
            self.createKeyPlugin = nil
        })
    }

    func fetchMac() {
        if self.fetchMacTimer != nil {
            self.fetchMacTimer?.invalidate()
            self.fetchMacTimer = nil
        }
        guard let currentVin: String = self.vehicle.vin else {
            return
        }
        startTimerMacAddress(currentVin: currentVin)
    }

    func startTimerMacAddress(currentVin: String) {
        let timer = Timer(timeInterval: 5, repeats: true) { [weak self] _ in
            if let digitalKey: DigitalKey = self?.validBlePrivateKey() {
                if digitalKey.bleInfo?.macAddress != nil {
                    self?.fetchMacTimer?.invalidate()
                    self?.fetchMacTimer = nil
                    self?.bleInfo = digitalKey.bleInfo
                    return
                }
            }
            self?.requestMacAddressOnce(currentVin: currentVin, callBack: nil)
        }
        RunLoop.current.add(timer, forMode: .common)
        self.fetchMacTimer = timer
    }

    func requestMacAddressOnce(currentVin: String, callBack: ((_ isSuc: Bool) -> Void)?) {
        let responseCallback: BLEKeyHttpRequestCallback<BLEInfo> = { response in
            if (response.code == 200 && response.data != nil) {
                callBack?(true)
                let info = response.data!
                guard let macAddress: String = info.macAddress as? String else {
                    return
                }
                self.fetchMacTimer?.invalidate()
                self.fetchMacTimer = nil
                Log.i(tag:"DigitalKeyManager", "定时器下载到Mac地址:%@ vin:%@", macAddress, currentVin)
                var currentKey: DigitalKey? = self.validBlePrivateKey()
                if currentKey == nil {
                    let digitalKeyList = DigitalKey.queryDigitalKeyList(vin: currentVin)
                    for digitalKey: DigitalKey in digitalKeyList {
                        if digitalKey.vin == currentVin {
                            currentKey = digitalKey
                        }
                    }
                }
                guard let targetKey: DigitalKey = currentKey else {
                    return
                }

                if targetKey.bleInfo?.macAddress != nil {
                    self.bleInfo = info
                    return
                }
                targetKey.bleInfo = info
                targetKey.save()
                self.appendDigitalKey(digitalKey: targetKey)
                self.bleInfo = info
            } else {
                callBack?(false)
            }
        }
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.bleInfo, payload: ["vin": currentVin], callback: responseCallback)
    }

    func stopTimerMacAddress() {
        if self.fetchMacTimer != nil {
            self.fetchMacTimer?.invalidate()
            self.fetchMacTimer = nil
        }
    }

