{
  "accessTokens": [
    "tenant",
    "user"
  ],
  "description": "获取知识空间节点信息",
  "docUrl": "https://open.feishu.cn/document/ukTMukTMukTM/uUDN04SN0QjL1QDN/wiki-v2/space/get_node",
  "httpMethod": "GET",
  "id": "spaces.get_node",
  "parameters": {
    "obj_type": {
      "default": "wiki",
      "description": "文档类型。不传时默认以 wiki 类型查询。",
      "enumName": "ObjTypeForQuery",
      "example": "docx",
      "location": "query",
      "options": [
        {
          "description": "旧版文档",
          "value": "doc"
        },
        {
          "description": "新版文档",
          "value": "docx"
        },
        {
          "description": "表格",
          "value": "sheet"
        },
        {
          "description": "思维导图",
          "value": "mindnote"
        },
        {
          "description": "多维表格",
          "value": "bitable"
        },
        {
          "description": "文件",
          "value": "file"
        },
        {
          "description": "幻灯片",
          "value": "slides"
        },
        {
          "description": "知识库节点",
          "value": "wiki"
        }
      ],
      "required": false,
      "type": "string"
    },
    "token": {
      "default": "",
      "description": "知识库节点或对应云文档的实际 token。;- 知识库节点 token：如果 URL 链接中 token 前为 wiki，该 token 为知识库的节点 token。;- 云文档实际 token：如果 URL 链接中 token 前为 docx、base、sheets 等非 wiki 类型，则说明该 token 是当前云文档的实际 token。;;了解更多，请参考[文档常见问题-如何获取云文档资源相关 token（id）](https://open.feishu.cn/document/ukTMukTMukTM/uczNzUjL3czM14yN3MTN)。;;**注意**：;;使用云文档 token 查询时，需要对 obj_type 参数传入文档对应的类型。",
      "example": "wikcnKQ1k3p******8Vabcef",
      "location": "query",
      "required": true,
      "type": "string"
    }
  },
  "path": "spaces/get_node",
  "responseBody": {
    "node": {
      "description": "节点信息",
      "properties": {
        "creator": {
          "annotations": [
            "readOnly"
          ],
          "description": "文档创建者",
          "example": "ou_xxxxx",
          "required": false,
          "type": "string"
        },
        "has_child": {
          "annotations": [
            "readOnly"
          ],
          "description": "是否有子节点",
          "example": "false",
          "required": false,
          "type": "boolean"
        },
        "node_create_time": {
          "annotations": [
            "readOnly"
          ],
          "description": "节点创建时间",
          "example": "1642402428",
          "required": false,
          "type": "string"
        },
        "node_creator": {
          "annotations": [
            "readOnly"
          ],
          "description": "节点创建者",
          "example": "ou_xxxxx",
          "required": false,
          "type": "string"
        },
        "node_token": {
          "annotations": [
            "readOnly"
          ],
          "description": "知识库节点 token，如果 URL 链接中 token 前为 wiki，该 token 为知识库的节点 token。",
          "example": "wikcnKQ1k3p******8Vabcef",
          "required": false,
          "type": "string"
        },
        "node_type": {
          "description": "节点类型",
          "enum": [
            "origin",
            "shortcut"
          ],
          "enumName": "NodeType",
          "example": "origin",
          "options": [
            {
              "description": "实体",
              "value": "origin"
            },
            {
              "description": "快捷方式",
              "value": "shortcut"
            }
          ],
          "required": true,
          "type": "string"
        },
        "obj_create_time": {
          "annotations": [
            "readOnly"
          ],
          "description": "文档创建时间",
          "example": "1642402428",
          "required": false,
          "type": "string"
        },
        "obj_edit_time": {
          "annotations": [
            "readOnly"
          ],
          "description": "文档最近编辑时间",
          "example": "1642402428",
          "required": false,
          "type": "string"
        },
        "obj_token": {
          "annotations": [
            "readOnly"
          ],
          "description": "节点的实际云文档的 token，如果 URL 链接中 token 前为 docx、base、sheets 等非 wiki 类型，则说明该 token 是当前云文档的实际 token。如果要获取或编辑节点内容，需要使用此 token 调用对应的接口。可根据 obj_type 判断属于哪种文档类型。",
          "example": "doccnzAaOD******Wabcdef",
          "required": false,
          "type": "string"
        },
        "obj_type": {
          "description": "文档类型，对于快捷方式，该字段是对应的实体的obj_type。",
          "enum": [
            "doc",
            "sheet",
            "mindnote",
            "bitable",
            "file",
            "docx",
            "slides"
          ],
          "enumName": "ObjType",
          "example": "doc",
          "options": [
            {
              "description": "旧版文档",
              "value": "doc"
            },
            {
              "description": "表格",
              "value": "sheet"
            },
            {
              "description": "思维导图",
              "value": "mindnote"
            },
            {
              "description": "多维表格",
              "value": "bitable"
            },
            {
              "description": "文件",
              "value": "file"
            },
            {
              "description": "新版文档",
              "value": "docx"
            },
            {
              "description": "幻灯片",
              "value": "slides"
            }
          ],
          "required": true,
          "type": "string"
        },
        "origin_node_token": {
          "description": "快捷方式对应的实体node_token，当节点为快捷方式时，该值不为空。",
          "example": "wikcnKQ1k3p******8Vabcef",
          "required": false,
          "type": "string"
        },
        "origin_space_id": {
          "annotations": [
            "readOnly"
          ],
          "description": "快捷方式对应的实体所在的space id",
          "example": "6946843325487912356",
          "required": false,
          "type": "string"
        },
        "owner": {
          "annotations": [
            "readOnly"
          ],
          "description": "文档所有者",
          "example": "ou_xxxxx",
          "required": false,
          "type": "string"
        },
        "parent_node_token": {
          "description": "父节点 token。若当前节点为一级节点，父节点 token 为空。",
          "example": "wikcnKQ1k3p******8Vabcef",
          "required": false,
          "type": "string"
        },
        "space_id": {
          "annotations": [
            "readOnly"
          ],
          "description": "知识空间 ID。获取方式参考[知识库概述](https://open.feishu.cn/document/ukTMukTMukTM/uUDN04SN0QjL1QDN/wiki-overview)。",
          "example": "6946843325487912356",
          "required": false,
          "type": "string"
        },
        "title": {
          "description": "文档标题",
          "example": "标题",
          "required": false,
          "type": "string"
        }
      },
      "ref": "node",
      "required": false,
      "type": "object"
    }
  },
  "scopes": [
    "wiki:wiki",
    "wiki:wiki:readonly",
    "wiki:node:read"
  ]
}

